/**
 * @summary Get experiment results and metrics
 */
export const getGetExperimentResultsUrl = (
  params: GetExperimentResultsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/experiments/results?${stringifiedParams}`
    : `/api/experiments/results`;
};

export const getExperimentResults = async (
  params: GetExperimentResultsParams,
  options?: RequestInit,
): Promise<ExperimentResults> => {
  return customFetch<ExperimentResults>(getGetExperimentResultsUrl(params), {
    ...options,
    method: "GET",
  });
};

